import React, { useMemo, useState, useEffect } from 'react';

interface SelectionCommitteeBackgroundProps {
    imageUrl: string | undefined;
    className?: string;
    /** Manual X position for object-position (0-100). If not provided, uses random value between 20-60 */
    objectPositionX?: number;
    /** Manual Y position for object-position (0-100). If not provided, uses random value between 10-60 */
    objectPositionY?: number;
    /** Transform scale value. Defaults to 1.8 */
    scale?: number;
    /** Image opacity (0-1). Defaults to 0.25 */
    opacity?: number;
    /**
     * Which side the image is anchored to and fades away from.
     * 'left' (default): image on the left, fades out to the right.
     * 'right': image mirrored on the right, fades out to the left.
     */
    align?: 'left' | 'right';
}

const SelectionCommitteeBackground: React.FC<SelectionCommitteeBackgroundProps> = ({
    imageUrl,
    className = '',
    objectPositionX,
    objectPositionY,
    scale = 1.8,
    opacity = 0.25,
    align = 'left',
}) => {
    const segment = useMemo(() => {
        if (!imageUrl || imageUrl.includes('N/A')) return null;
        
        return {
            poster: imageUrl,
            clipX: objectPositionX ?? (20 + Math.random() * 40),
            clipY: objectPositionY ?? (10 + Math.random() * 50),
        };
    }, [imageUrl, objectPositionX, objectPositionY]);

    const [loaded, setLoaded] = useState(false);

    // Reset the fade-in whenever the image source changes
    useEffect(() => {
        setLoaded(false);
    }, [segment?.poster]);

    if (!segment) return null;

    const isRight = align === 'right';
    const fadeDirection = isRight ? 'to left' : 'to right';
    const maskGradient = `linear-gradient(${fadeDirection}, black 0%, black 20%, transparent 100%)`;

    return (
        <div className={`absolute inset-0 overflow-hidden pointer-events-none rounded-lg ${className}`}>
            <div
                className={`absolute top-0 bottom-0 w-2/3 h-full ${isRight ? 'right-0' : 'left-0'}`}
                style={{
                    maskImage: maskGradient,
                    WebkitMaskImage: maskGradient,
                }}
            >
                <img
                    src={segment.poster}
                    alt=""
                    aria-hidden="true"
                    className="w-full h-full object-cover transition-opacity duration-700 ease-out"
                    style={{
                        objectPosition: `${segment.clipX}% ${segment.clipY}%`,
                        transform: `scale(${scale})${isRight ? ' scaleX(-1)' : ''}`,
                        opacity: loaded ? opacity : 0,
                    }}
                    loading="lazy"
                    onLoad={() => setLoaded(true)}
                    ref={(node) => { if (node?.complete) setLoaded(true); }}
                />
            </div>
        </div>
    );
};

export default SelectionCommitteeBackground;